sqlMap.insert:
INSERT INTO WeavePattern (
    WeaveName, WeaveCode, RepeatX, RepeatY,
    Cells, WarpColors, WeftColors, SavedAt
) VALUES (
    @name, @code, @repeatX, @repeatY,
    @cells, @warpColors, @weftColors, @savedAt
);

sqlMap.select:
SELECT Idx, WeaveName, WeaveCode, SavedAt
FROM WeavePattern
ORDER BY Idx DESC;

SELECT * FROM WeavePattern
WHERE WeaveName = @name
LIMIT 1;
